#include <bits/stdc++.h>using namespace std;int main(){    string s;    cin >> s;    int up=0;    int lw=0;    for(char ch:s){        if(ch>= 'a' && ch<='z'){            lw++;        }        else{            up++;        }    }    if(up>lw){        for(char &c: s){            c= toupper(c);        }    }    else{        for(char &c:s){            c=tolower(c);        }    }    cout << s;    return 0;}